-- KittyRaiser one-paste installer
-- Generated by build_loader.py from src/.
-- Paste into the Studio command bar (View > Command Bar) and press Enter.
-- Build version: dev (part 2)

local function ensure(parent, className, name)
    local existing = parent:FindFirstChild(name)
    if existing and existing.ClassName == className then return existing end
    if existing then existing:Destroy() end
    local inst = Instance.new(className)
    inst.Name = name
    inst.Parent = parent
    return inst
end

local function ensureFolder(parent, name)
    return ensure(parent, 'Folder', name)
end

local function writeScript(parentPath, className, source)
    -- parentPath is a list like {'ReplicatedStorage','Modules','GameConfig'}
    local node = game
    for i = 1, #parentPath - 1 do
        local segment = parentPath[i]
        local nxt = node:FindFirstChild(segment)
        if not nxt then
            -- Top-level services already exist; create only Folder children.
            nxt = ensureFolder(node, segment)
        end
        node = nxt
    end
    local leafName = parentPath[#parentPath]
    local s = ensure(node, className, leafName)
    s.Source = source
    return s
end

local INSTALLED = 0
local function W(parentPath, className, source)
    writeScript(parentPath, className, source)
    INSTALLED = INSTALLED + 1
end

