spawnBtn.TextScaled = true
spawnBtn.TextColor3 = Color3.fromRGB(255, 255, 255)
spawnBtn.TextStrokeTransparency = 0
spawnBtn.TextStrokeColor3 = Color3.fromRGB(0, 60, 30)
